            print(n, 'equals', x, '*', n//x)
            break
    else:
        print(n, 'is a prime number')

def my_generator():
    for i in range(1000000):
        yield i

for val in my_generator():
    if val > 5: break
    print(val)

fruits = ["apple", "banana"]
